// Helper: collect a node's items as an array of rows.
function rows(nodeName) {
  return $(nodeName).all().map(i => i.json).filter(o => o && Object.keys(o).length > 0);
}

const promptRows = rows('Get Prompt');
const byName = Object.fromEntries(promptRows.map(p => [p.name, p.content]));
const promptOrder = [
  '10-behavioural-training-sale',
  '15-conversational-data-capture-sale',
  '20-domain-knowledge-wine',
  '30-profile-account',
  '40-playbook-account'
];
const stablePrompt = promptOrder.map(n => byName[n]).filter(Boolean).join('\n\n---\n\n');

// Contact context from Get Contact (silent — never call attention to having it).
// IMPORTANT: replace the field IDs below with the actual GHL custom-field IDs
// from Settings → Custom Fields after the fields are created.
const FIELD_ID = {
  ai_paused: 'GsQWJpXPmL4UpFUyzuOe',
  whatsapp_preferred: 'cZnCWMR3VsZW0YXXcxGL',
  return_channels_captured_at: 'kE3148Mfthnf3UHEPb4N',
  last_wines_discussed: 'fjnOTKILzjC3VCeS6bpw',
  team_notes: 'MOQaRVRvj1KiHEzIlmuU',
};
const contactItems = $('Get Contact').all().map(i => i.json).filter(Boolean);
const contact = contactItems[0]?.contact || {};
const customFields = contact.customFields || [];
const getField = (id) => (customFields.find(f => f.id === id) || {}).value;

const isPlaceholderName = (s) => !s || /^(guest|visitor|unknown|anonymous)/i.test(String(s).trim());
const realFirstName = isPlaceholderName(contact.firstName) ? '' : contact.firstName;
const contactCtx = [];
if (realFirstName) contactCtx.push(`Customer first name: ${realFirstName}`);
if (contact.email && !/visitor|guest/i.test(contact.email)) contactCtx.push(`Email on record: ${contact.email}`);
if (contact.phone) contactCtx.push(`Phone on record: ${contact.phone}`);
if (getField(FIELD_ID.whatsapp_preferred) === 'Yes') contactCtx.push('Customer prefers WhatsApp.');
if (getField(FIELD_ID.last_wines_discussed)) contactCtx.push(`Previously discussed: ${getField(FIELD_ID.last_wines_discussed)}`);
const teamNotesRaw = getField(FIELD_ID.team_notes);
if (teamNotesRaw) {
  try {
    const notes = JSON.parse(teamNotesRaw);
    if (Array.isArray(notes) && notes.length) {
      contactCtx.push(`Team notes received during this conversation that you should fold into your response:\n${notes.map(n => `- ${n}`).join('\n')}`);
    }
  } catch (_e) { /* not JSON yet */ }
}
const contactBlock = contactCtx.length ? `\n\n## Contact context\n${contactCtx.join('\n')}` : '';

const wines = rows('Search Wines');
const history = rows('Get History').slice().reverse()
  .filter((r) => {
    if (r.role !== 'assistant') return true; // always keep customer turns
    let md = r.metadata;
    if (typeof md === 'string') { try { md = JSON.parse(md); } catch (_e) { md = {}; } }
    if (md && md._agent && md._agent.error === true) return false; // drop logged fallback/outage turns
    if (typeof r.content === 'string' && /^sorry\s*[\u2014-]\s*i'?m having a moment/i.test(r.content)) return false;
    return true;
  })
  .map((r) => ({ role: r.role, content: r.content }));
const extract = $('Extract').first().json;

const wineBlock = wines.length
  ? '## Available wines for this conversation\n' + wines.map((w, i) => {
      const head = `${i + 1}. **${w.title}** — ${[w.varietal, w.vintage].filter(Boolean).join(' ')}` + (w.price ? `, R${w.price}` : '') + (w.shopify_variant_id ? ` [variant_id: ${w.shopify_variant_id} — use this for check_stock/add_to_cart; never say it aloud]` : '');
      const body = w.description ? `\n   ${w.description}` : '';
      const pair = w.pairings ? `\n   Pairings: ${w.pairings}.` : '';
      const award = w.awards ? ` Awards: ${w.awards}.` : '';
      return head + body + pair + award;
    }).join('\n')
  : '';

// Cache the stable layered prompt + contact context (changes rarely per
// conversation). Wine block lives in an uncached trailing block.
const systemBlocks = [
  { type: 'text', text: stablePrompt + contactBlock, cache_control: { type: 'ephemeral' } }
];
if (wineBlock) {
  systemBlocks.push({ type: 'text', text: wineBlock });
}

const userMsg = { role: 'user', content: `[channel: ${extract.channel}]\n${extract.message}` };
const messages = [...history, userMsg];

return [{ json: {
  systemBlocks,
  messages,
  tenant_id: $('Get Tenant').first().json.id,
  contact_id: extract.contact_id,
  channel: extract.channel,
  channel_ghl: extract.channel_ghl,
  message: extract.message,
  retrieved_wine_ids: wines.map(w => w.id)
} }];

